# ANTI-PATTERN: Single-pass retrieval with no adaptation
class NaiveRAGBatter:
    def generate_response(self, query):
        # Retrieve once, generate once—no agent decision loop
        docs = self.retriever.fetch(query, top_k=5)
        response = self.llm.generate(
            context=docs,
            query=query
        )
        return response  # Returns without checking confidence

# BEST PRACTICE: Agentic loop with confidence-based iteration
class AdaptiveRAGBatter:
    def generate_response(self, query, max_iterations=3):
        context_runs = []  # Like tracking multiple innings
        confidence_threshold = 0.75

        for iteration in range(max_iterations):
            # Retrieve with relevance scoring
            docs = self.retriever.fetch(
                query, 
                top_k=5,
                return_scores=True
            )

            # Generate with explicit confidence output
            response, confidence = self.llm.generate_with_confidence(
                context=docs,
                query=query
            )

            context_runs.append({
                'iteration': iteration,
                'response': response,
                'confidence': confidence,
                'doc_quality': min([score for _, score in docs])
            })

            # Agent decision: continue if low confidence
            if confidence > confidence_threshold:
                return response  # Wicket secured

            if iteration < max_iterations - 1:
                # Reformulate query for next retrieval cycle
                query = self._reformulate_query(response, docs)

        # Return best attempt from all runs
        return max(context_runs, key=lambda x: x['confidence'])['response']

    def _reformulate_query(self, response, previous_docs):
        # Ask LLM: "What additional context would improve this?"
        return self.llm.reformulate(
            original_query=query,
            current_response=response,
            retrieved_context=previous_docs
        )
